3	import com.sankuai.meituan.util.ConfigUtilAdapter;
4	import com.sankuai.meituan.waimai.bizad.billing.platform.domain.sdf.SdfRatioModeEnum;
5	import com.sankuai.meituan.waimai.bizad.platform.billing.domain.sdf.model.SdfAccountActivityInfo;
