29	
30	/**
31	 * @ClassName GetSdfSignInfoPopupParamsTest
32	 * @Description 测试 getSdfSignInfo 接口中新增的3个弹窗参数字段计算逻辑：
33	 *   - redPacketIssueDays（红包发放总天数）
34	 *   - redPacketInflationRate（红包膨胀系数）
35	 *   - transferInRatio（转入比例）
36	 *
37	 * 对应需求：#94388352 随单返首页弹窗一键开启
38	 * 接口：AdAccountServiceImpl#getSdfSignInfo (RPC)
39	 *
40	 * 测试维度：
41	 *   TC01 - 有活动，有 benefitRule stage → redPacketIssueDays = max(endOffsetDays) 字符串
42	 *   TC02 - 有活动，benefitRule 为 null → redPacketIssueDays = null
43	 *   TC03 - 有活动，stage 列表为空 → redPacketIssueDays = null
44	 *   TC04 - 有活动，cashRatioDecimal 正常 → redPacketInflationRate = (red+cash)/cash 保留2位小数
45	 *   TC05 - 有活动，cashRatioDecimal = 0 → redPacketInflationRate = null（避免除零）
46	 *   TC06 - FIXED 模式 → transferInRatio = "30%"
47	 *   TC07 - CUSTOM 模式 → transferInRatio = "30%"（与 FIXED 相同，用 cashRatioDecimal 基础值）
48	 *   TC08 - DYNAMIC 模式 → transferInRatio = "5%~8%"（cashRatioDecimal ~ cashRatioDecimal+ratioVariable）
49	 *   TC09 - 无活动（activityInfo = null）→ 三个字段均不设置（为 null）
50	 * @Author ai-coding
51	 * @Date 2026-05-20
52	 */
53	@RunWith(MockitoJUnitRunner.class)
54	public class GetSdfSignInfoPopupParamsTest {
55	
56	    @InjectMocks
57	    private AdAccountSdfAppService adAccountSdfAppService;
58	
59	    @Mock
60	    private AdAccountSdfService adAccountSdfService;
61	
62	    @Mock
63	    private SdfRatioConfigFutureRepository sdfRatioConfigFutureRepository;
64	
65	    private MockedStatic<ConfigUtilAdapter> mockedConfigUtil;
66	
67	    private static final long PARTNER_ID = 8001L;
68	    private static final int PARTNER_TYPE = 1;
69	    private static final long ACTIVITY_ID = 500L;
70	
71	    @Before
72	    public void setUp() {
73	        ReflectionTestUtils.setField(adAccountSdfAppService, "self", adAccountSdfAppService);
74	        mockedConfigUtil = Mockito.mockStatic(ConfigUtilAdapter.class);
75	        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString(), anyInt())).thenReturn(2);
76	        mockedConfigUtil.when(() -> ConfigUtilAdapter.getInt(anyString())).thenReturn(2);
77	        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(eq("sdf_ratio_max_cash"), anyString())).thenReturn("50");
78	        mockedConfigUtil.when(() -> ConfigUtilAdapter.getString(anyString(), anyString()))
79	                .thenAnswer(inv -> inv.getArgument(1));
80	    }
81	
82	    @After
83	    public void tearDown() {
84	        if (mockedConfigUtil != null) {
85	            mockedConfigUtil.close();
86	        }
87	    }
88	
89	    // ============================================================
90	    // Helpers
91	    // ============================================================
92	
93	    private SdfAccountActivityInfo buildActivityInfo(Integer ratioMode,
94	                                                      BigDecimal cashRatioDecimal,
95	                                                      BigDecimal redRatioDecimal,
96	                                                      BigDecimal ratioVariable,
97	                                                      SdfBenefitRule benefitRule) {
98	        SdfAccountActivityInfo info = new SdfAccountActivityInfo();
99	        info.setActivityId(ACTIVITY_ID);
100	        info.setPartnerId(PARTNER_ID);
101	        info.setPartnerType(PARTNER_TYPE);
102	        info.setRatioMode(ratioMode);
103	        info.setCashRatioDecimal(cashRatioDecimal);
104	        info.setRedRatioDecimal(redRatioDecimal);
105	        info.setRatioVariable(ratioVariable);
106	        info.setBenefitRule(benefitRule);
107	        info.setStartDate(20260101);
108	        info.setEndDate(20991231);
109	        return info;
110	    }
111	
112	    private SdfBenefitRule buildBenefitRuleWithStages(int... endOffsetDaysArr) {
113	        SdfBenefitRule rule = new SdfBenefitRule();
114	        java.util.List<SdfRedPackStage> stages = new java.util.ArrayList<>();
115	        for (int i = 0; i < endOffsetDaysArr.length; i++) {
116	            SdfRedPackStage stage = new SdfRedPackStage();
117	            stage.setStartOffsetDays(i * 10);
118	            stage.setEndOffsetDays(endOffsetDaysArr[i]);
119	            stage.setRatio(new BigDecimal("0.05"));
120	            stages.add(stage);
121	        }
122	        rule.setSdfRedPackStageRules(stages);
123	        return rule;
124	    }
125	
126	    // ============================================================
127	    // TC01: 有活动 + 有 benefitRule stage → redPacketIssueDays = max(endOffsetDays)
128	    // ============================================================
129	    @Test
130	    public void tc01_withActivity_benefitRuleHasStages_redPacketIssueDaysEqualsMaxEndOffset() {
131	        // stages: endOffsetDays = 10, 20, 30 → max = 30
132	        SdfBenefitRule rule = buildBenefitRuleWithStages(10, 20, 30);
133	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
134	                SdfRatioModeEnum.FIXED.getMode(),
135	                new BigDecimal("5"),
136	                new BigDecimal("2"),
137	                null,
138	                rule);
139	
140	        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);
141	
142	        assertNotNull("redPacketIssueDays 应非 null", result);
143	        assertEquals("redPacketIssueDays 应等于 stages 中最大 endOffsetDays", "30", result);
144	    }
145	
146	    // ============================================================
147	    // TC02: 有活动，benefitRule = null → redPacketIssueDays = null
148	    // ============================================================
149	    @Test
150	    public void tc02_withActivity_benefitRuleNull_redPacketIssueDaysIsNull() {
151	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
152	                SdfRatioModeEnum.FIXED.getMode(),
153	                new BigDecimal("5"),
154	                new BigDecimal("2"),
155	                null,
156	                null);
157	
158	        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);
159	
160	        assertNull("benefitRule 为 null 时 redPacketIssueDays 应为 null", result);
161	    }
162	
163	    // ============================================================
164	    // TC03: 有活动，stage 列表为空 → redPacketIssueDays = null
165	    // ============================================================
166	    @Test
167	    public void tc03_withActivity_stagesEmpty_redPacketIssueDaysIsNull() {
168	        SdfBenefitRule rule = new SdfBenefitRule();
169	        rule.setSdfRedPackStageRules(Collections.emptyList());
170	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
171	                SdfRatioModeEnum.FIXED.getMode(),
172	                new BigDecimal("5"),
173	                new BigDecimal("2"),
174	                null,
175	                rule);
176	
177	        String result = adAccountSdfAppService.calcRedPacketIssueDays(activityInfo);
178	
179	        assertNull("stage 列表为空时 redPacketIssueDays 应为 null", result);
180	    }
181	
182	    // ============================================================
183	    // TC04: 正常 cashRatioDecimal → redPacketInflationRate = (red+cash)/cash 保留2位小数
184	    //   cashRatioDecimal=5, redRatioDecimal=2 → (5+2)/5 = 1.40
185	    // ============================================================
186	    @Test
187	    public void tc04_normalRatios_inflationRateCalculatedCorrectly() {
188	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
189	                SdfRatioModeEnum.FIXED.getMode(),
190	                new BigDecimal("5"),
191	                new BigDecimal("2"),
192	                null,
193	                null);
194	
195	        String result = adAccountSdfAppService.calcInflationRate(activityInfo);
196	
197	        assertNotNull("redPacketInflationRate 应非 null", result);
198	        assertEquals("(5+2)/5 = 1.40", "1.40", result);
199	    }
200	
201	    // ============================================================
202	    // TC05: cashRatioDecimal = 0 → redPacketInflationRate = null（避免除零）
203	    // ============================================================
204	    @Test
205	    public void tc05_cashRatioZero_inflationRateIsNull() {
206	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
207	                SdfRatioModeEnum.FIXED.getMode(),
208	                BigDecimal.ZERO,
209	                new BigDecimal("2"),
210	                null,
