235	
236	    // ============================================================
237	    // TC07: CUSTOM 模式 → transferInRatio = "30%"（与 FIXED 相同，用 cashRatioDecimal）
238	    // ============================================================
239	    @Test
240	    public void tc07_customMode_transferInRatioIsCashRatioWithPercent() {
