253	
254	    // ============================================================
255	    // TC08: DYNAMIC 模式 → transferInRatio = "cashRatioDecimal%~(cashRatioDecimal+ratioVariable)%"
256	    //   cashRatioDecimal=5, ratioVariable=3 → "5%~8%"
257	    // ============================================================
258	    @Test
259	    public void tc08_dynamicMode_transferInRatioIsRange() {
260	        SdfAccountActivityInfo activityInfo = buildActivityInfo(
261	                SdfRatioModeEnum.DYNAMIC.getMode(),
262	                new BigDecimal("5"),
263	                new BigDecimal("2"),
264	                new BigDecimal("3"),
