267	        String result = adAccountSdfAppService.calcTransferInRatio(activityInfo);
268	
269	        assertNotNull(result);
270	        assertEquals("DYNAMIC 模式 transferInRatio 应为区间 cashRatioDecimal%~(cash+variable)%",
271	                "5%~8%", result);
