        long couponAmount = wmCouponProxy.getCouponAmountByTemplateId(couponTemplateId, benefitTemplateId);
        couponAmoutMap.put(sdfCouponInfo, couponAmount);
    }
    sdfCouponInfo.setCouponAmount(couponAmoutMap.get(sdfCouponInfo));
    rule.setSdfCouponInfo(sdfCouponInfo);
}

