namespace java com.sankuai.meituan.waimai.bizad.billing.platform.vo.sdf

include './Result.thrift'
include './AdAccountVO.thrift'

/**
 * 随单返功能配置DTO
 */
struct SdfFeatureConfigDTO {
  1: i64 activityId,                  // 活动ID
  2: string activityName,             // 活动名称
  3: i32 startDate,                   // 开始日期
  4: i32 endDate,                     // 结束日期
  5: string cashRatio,                // 现金比例
  6: i32 cashCycleDate,               // 现金周期日期
  7: i32 status,                      // 状态
  8: i32 systemSign,                  // 系统标识
  9: string redRatio,                 // 红包比例
  10: i32 redCycleDate,               // 红包周期日期
  11: string stage2RedRatio,          // 第二阶段红包比例
  12: i32 stage2RedCycleDate,         // 第二阶段红包周期日期
  13: i32 stage2RedKeepSignDays,      // 第二阶段红包保持签约天数
  14: i64 couponTemplateId,           // 券模板ID
  15: i64 benefitTemplateId,          // 权益模板ID
  16: optional i32 adProdType,                 // 开通投放的产品类型
  17: string guideText                // 引导文案
  18: list<i64> partnerIds;
  19: i32 partnerType;
  20: optional i32 source;
  21: optional i32 ratioMode,      // 档位模式 0=固定比例 1=动态档位 2=自定义档位
  22: optional string ratioVariable // 档位变量 y，CUSTOM 模式下比例下限 = max(1%, cashRatio - ratioVariable)
}

/**
 * 随单返灰度配置DTO
 */
struct SdfGrayConfigDTO {
  1: i32 terminationType,             // 终止类型
  2: i32 withdrawType,                // 提现类型
  3: list<i64> partnerIds,               // 账户IDs
  4: i32 partnerType                  // 账户类型
}

struct SdfAggregateInfoQueryReq {
    1: i64 partnerId;
    2: i32 partnerType;
    /**
     * @FieldDoc(
     *     description = "登录账号的ID，店侧是美团账号ID"
     * )
     */
    3: i64 loginAccountId;
    /**
     * @FieldDoc(
     *     description = "家侧外卖门店ID，店侧点评门店Id"
     * )
     */
    4: list<i64> poiIds;
    5: i64 ruleId;
}

struct SdfConfigInfoDTO {
    1: string poiName;//门店名称
    2: i32 startDate;//可签约开始时间
    3: i32 endDate;//可签约结束时间
    4: i32 cashCycleDate;//转入现金持续时间
    5: i32 redCycleDate;//转入红包持续时间
    6: string cashRatioDecimal;// 现金返还比例，用于替换原有cashRatio字段
    7: string redRatioDecimal;// 红包返还比例，用于替换原有redRatio字段
    8: string guideText; // 引导文案
    9: AdAccountVO.SdfBenefitRuleDTO sdfBenefitRuleDTO; // 权益规则
    10: AdAccountVO.SdfLaunchStrategyDTO sdfLaunchStrategyDTO; // 投放策略
    /**
     * @FieldDoc(
     *     description = "随单返活动ID, 与营销活动是两个概念"
     * )
     */
    11: i64 activityId;
    /**
     * @FieldDoc(
     *     description = "随单返功能配置ID"
     * )
     */
    12: i64 featureConfigId;
    13: i64 partnerId;
    14: i32 partnerType;
    15: bool canWithdraw;
    16: bool canSelfTermination;
}


struct SdfAggregateInfoDTO {
    1: SdfConfigInfoDTO configInfo;
    2: AdAccountVO.SdfSignInfoDTO ruleInfo;
    3: list<AdAccountVO.SdfBillDTO> billInfos;
}

struct SdfAggregateInfoResp {
    1: Result.Result result;
    2: SdfAggregateInfoDTO sdfAggregateInfo;
}

struct SdfSignReq {
    1: i64 partnerId;
    2: i32 partnerType;
    3: i64 loginAccountId;
    4: list<i64> dpShopIds;
    5: i64 featureConfigId;
    6: i64 ruleId;
    7: i32 operateType;
    8: AdAccountVO.SdfSignExtraInfoDTO extraInfo;
    9: optional string cashRatio; // 自定义档位签约时页面输入的转入比例，CUSTOM 模式时必填
}


struct SdfHistoryRuleInfoQueryReq {
    1: i64 partnerId;
    2: i32 partnerType;
}

struct SdfRuleOverviewInfoDTO {
    1: i64 ruleId;    // 协议id
    2: i32 signDate;  // 签约时间,yyyyMMdd格式
    3: i32 startDate; // 协议开始时间,yyyyMMdd格式
    4: i32 endDate;   // 协议结束时间,yyyyMMdd格式
    5: i64 partnerId;
    6: i32 partnerType;
    7: i64 loginAccountId;
    8: i32 signStatus;
}

struct SdfOperateInfoDTO {
    1: i32 operateType;
    2: i64 acctId;
    3: string token;
    4: i32 platform;
    5: string ip;
    6: string mis;
    7: string remark;
    8: string accountUserName;
    9: i64 planViewId;
    10: i64 operateTime;
}

struct SdPoiRuleAndOperateInfoDTO {
    1: list<i64> poiIds;
    2: SdfRuleOverviewInfoDTO ruleInfo;
    3: SdfOperateInfoDTO operateInfo;
}

struct SdfHistoryRuleInfoResp {
    1: Result.Result result;
    2: list<SdfRuleOverviewInfoDTO> sdfRuleInfos;
}


struct SdfTransferFlowQueryReq {
    1: i64 partnerId; // 商家id
    2: i32 partnerType; // 商家类型
    3: i32 startDate; // 开始时间, yyyyMMdd格式
    4: i32 endDate;// 结束时间, yyyyMMdd格式
    5: i64 ruleId;
}

struct SdfTransferFlowInfoDTO {
    1: i64 partnerId;
    2: i32 partnerType;
    3: i64 mtPoiId;
    4: i64 dpPoiId;
    5: i64 amount;
    6: i32 startDate;
    7: i32 endDate;
}

struct SdfTransferFlowResp {
    1: Result.Result result;
    2: list<SdfTransferFlowInfoDTO> transferFlowInfos;
}

struct SdfPoiRuleInfoResp {
    1: Result.Result result;
    2: map<i64, SdfRuleOverviewInfoDTO> poiSignInfoMap;
}

struct SdfRuleRelatedPoiResp {
    1: Result.Result result;
    2: list<i64> dpPoiIds;
}

struct SdfRulePageQueryReq {
    1: i64 partnerId;
    2: list<i32> partnerTypes;
    3: i32 pageNum;
    4: i32 pageSize;
    5: i32 active;
}

struct SdfRulePageQueryResp {
    1: Result.Result result;
    2: i32 total;
    3: i32 totalPage;
    4: i32 pageNum;
    5: i32 pageSize;
    6: list<SdPoiRuleAndOperateInfoDTO> operateInfos;
}

struct SdfGrayConfigResp {
    1: Result.Result result;
    2: SdfGrayConfigDTO grayConfig;
}

struct CanShowSdfReq {
    1: i64 mtAccountId;
    2: list<i64> ddAdAccountIds;
    3: list<i64> dpPoiIds;
}

struct CanShowSdfResp {
    1: Result.Result result;
    2: bool canMtAccountShow;
    3: set<i64> canShowDdAdAccountIds;
    4: set<i64> canShowDpPoiIds;
    5: map<AdAccountVO.PartnerDTO, AdAccountVO.SdfBenefitRuleDTO> benefitMap;
}

struct DdShopAccountUpgradeResp {
    1: Result.Result result;
    2: map<i64, bool> canUpgradeMap;
}

/**
 * 随单返比例配置，用于运营批量导入（importSdfRatioConfig）
 */
struct SdfRatioConfigDTO {
    1: i64 activityId;     // 随单返活动 ID
    2: i64 partnerId;      // 商家/门店 ID
    3: i32 partnerType;    // 商家类型 1=美团账户 2=点评账户
    4: string cashRatio;   // 转入现金比例，如 "0.08"
    5: i32 source;         // 来源 1=运营导入 2=商家自助
    6: string operator;    // 操作人 MIS 号
}

/**
 * 商家自助修改随单返转入比例请求
 */
struct SdfModifyReq {
    1: i64 partnerId;      // 商家/门店 ID
    2: i32 partnerType;    // 商家类型 1=美团账户 2=点评账户
    3: string cashRatio;   // 期望设置的比例，如 "0.06"；范围 [max(1%,x-y%), 50%]
    4: string operator;    // 操作人标识
    5: optional i32 operateType; // 操作类型
}

