public int batchCreateSdfActivityAndSign(List<SdfAdAccountActivity> activityList) {
    try {
        int ret = adAccountSdfService.createSdfActivity(activityList);
        if (ret <= 0) {
            return ret;
        }
        activityList.stream().filter(activity -> activity.getSystemSign() >= 1).forEach(
                e -> {
                    Result result = saveSdfSign(e.getPartnerId(), e.getPartnerType(), SdfAdAccountSignOperateTypeEnum.SYSTEM_SIGN.getType(), null);
                    if (!result.isSuccess()) {
                        log.error("[AdAccountSdfAppService.createBatchSdfActivity] saveSdfSign failed with activity:{}", e);
                    }
                }
        );
        return ret;
    } catch (Exception e) {
        log.error("[AdAccountSdfAppService.createBatchSdfActivity] exception caught with first activity:{},size:{}", activityList.get(0), activityList.size(), e);
    }
    return 0;
}

